#include <iostream>

void printLarger(const int& a, const int& b) {
    if (a >= b) {
        std::cout << a << '\n';
    } else {
        std::cout << b << '\n';
    }
}

int main() {
    int a, b;
    std::cin >> a >> b;
    printLarger(a, b);
    return 0;
}

