solution_code:
#include <iostream>

int countNegative(const int& a, const int& b, const int& c) {
    int count = 0;
    if (a < 0) ++count;
    if (b < 0) ++count;
    if (c < 0) ++count;
    return count;
}

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;
    std::cout << countNegative(a, b, c) << '\n';
    return 0;
}
